css:
@page {
  size: A4; margin: 14mm 16mm 18mm 16mm;
  @bottom-left { content: "Beispiel Handels GmbH · Marktplatz 1 · 10115 Berlin \A Amtsgericht Charlottenburg · HRB 123456 \A Geschäftsführer: Max Beispiel"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; vertical-align: top; padding-top: 4mm; }
  @bottom-center { content: "Seite " counter(page) " von " counter(pages); font-size: 6.5pt; color: #8a8a8a; white-space: nowrap; vertical-align: top; padding-top: 4mm; }
  @bottom-right { content: "USt-IdNr. DE123456789 · St.-Nr. 13/456/78901 \A IBAN DE89 3704 0044 0532 0130 00 · BIC COBADEFFXXX"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; text-align: right; vertical-align: top; padding-top: 4mm; }
}

body { color: #0a2540; font-family: 'Helvetica', 'Arial', sans-serif; }
.num { font-variant-numeric: tabular-nums; }
.mono { font-family: 'Courier New', monospace; letter-spacing: -0.02em; }
.doc-header { display: block; margin: 0; }

/* Carrier band */
.lo-band { display: flex; align-items: center; justify-content: space-between; background: #0a2540; color: #fff; border-radius: 2.5mm; padding: 5mm 6mm; }
.lo-brand { display: flex; align-items: center; gap: 4mm; }
.lo-mark { height: 11mm; width: 11mm; display: block; }
.lo-brandname { font-size: 12pt; font-weight: 800; }
.lo-sub { font-size: 8pt; color: #9db4d4; margin-top: 0.4mm; }
.lo-doc { text-align: right; }
.lo-eyebrow { display: block; font-size: 8pt; letter-spacing: 0.22em; text-transform: uppercase; color: #f97316; font-weight: 700; }
.lo-docno { display: block; font-size: 15pt; font-weight: 800; margin-top: 0.6mm; }

/* Hero */
.lo-hero { display: flex; align-items: center; gap: 6mm; margin: 6mm 0; }
.lo-status { background: #f97316; color: #fff; font-size: 12pt; font-weight: 800; letter-spacing: 0.04em; text-transform: uppercase; padding: 2.5mm 6mm; border-radius: 999px; }
.lo-hero__facts { display: flex; gap: 10mm; }
.lo-k { display: block; font-size: 7pt; letter-spacing: 0.14em; text-transform: uppercase; color: #6b7c96; font-weight: 700; }
.lo-v { font-size: 11pt; font-weight: 700; }

/* Main */
.lo-main { display: flex; gap: 7mm; align-items: stretch; }
.lo-left { flex: 1 1 0; }
.lo-h2 { font-size: 8.5pt; letter-spacing: 0.12em; text-transform: uppercase; color: #1d4ed8; font-weight: 700; margin: 0 0 3mm; }
.lo-h2--mt { margin-top: 7mm; }

/* Route */
.lo-route { list-style: none; margin: 0; padding: 0; }
.lo-rstep { display: flex; gap: 5mm; position: relative; padding-bottom: 5.5mm; }
.lo-rstep::before { content: ""; position: absolute; left: 2.15mm; top: 3mm; bottom: -3.5mm; width: 0.7mm; background: #cdd9ee; z-index: 0; }
.lo-rstep:last-child::before { display: none; }
.lo-rstep--done::before { background: #1d4ed8; }
.lo-dot { position: relative; z-index: 1; flex: 0 0 5mm; width: 5mm; height: 5mm; border-radius: 50%; background: #cdd9ee; margin-top: 0.5mm; }
.lo-rstep--done .lo-dot { background: #1d4ed8; }
.lo-rstep--current .lo-dot { background: #f97316; box-shadow: 0 0 0 1.3mm #fde3cf; }
.lo-rstep__place { font-weight: 700; font-size: 10pt; display: block; }
.lo-rstep--pending .lo-rstep__place { color: #93a1b8; }
.lo-rstep__time { font-size: 8.5pt; color: #6b7c96; }
.lo-addr { font-size: 10pt; line-height: 1.5; }

/* Stub */
.lo-stub { flex: 0 0 56mm; background: #eef4ff; border: 1.5px dashed #9db4d4; border-radius: 3mm; padding: 5mm; text-align: center; }
.lo-stub__hd { font-size: 8pt; letter-spacing: 0.2em; text-transform: uppercase; font-weight: 800; color: #0a2540; margin-bottom: 3mm; }
.lo-qr { display: flex; justify-content: center; }
.lo-qr svg { width: 30mm; height: 30mm; }
.lo-stub__k { font-size: 7pt; letter-spacing: 0.12em; text-transform: uppercase; color: #6b7c96; font-weight: 700; margin-top: 3mm; }
.lo-stub__track { font-size: 10pt; font-weight: 700; margin-top: 1mm; }
.lo-stub__bc { margin: 3mm 0; }
.lo-stub__bc svg { width: 100%; height: 12mm; }
.lo-stub__meta { display: flex; justify-content: space-between; font-size: 9pt; font-weight: 700; border-top: 1px solid #cdd9ee; padding-top: 2.5mm; }

/* Packages table */
.lo-pkgs { width: 100%; border-collapse: collapse; }
.lo-pkgs thead th { font-size: 7pt; letter-spacing: 0.1em; text-transform: uppercase; color: #6b7c96; font-weight: 700; text-align: left; padding: 0 3mm 2.5mm; border-bottom: 1px solid #d4def0; }
.lo-pkgs tbody td { padding: 2.6mm 3mm; border-bottom: 1px solid #e8eefa; vertical-align: middle; font-size: 9.5pt; }
.lo-pno { color: #93a1b8; font-weight: 700; width: 14mm; }
.lo-pbc svg { height: 7mm; width: 38mm; display: block; }
.lo-pbc .mono { font-size: 7.5pt; color: #6b7c96; }
